definition.script:
pipeline {
    agent any
    options {
        timestamps()
        buildDiscarder(logRotator(numToKeepStr: '20'))
        timeout(time: 5, unit: 'MINUTES')
    }

    stages {
        stage('Checkout') {
            steps {
                echo "[backend-tests] starting build #${env.BUILD_NUMBER}"
                sh 'echo "Cloning aiops-thesis backend..." && sleep 1'
            }
        }
        stage('Unit tests') {
            steps {
                sh '''
                    set +e
                    echo "[backend-tests] running pytest..."
                    PICK=$((RANDOM % 4))
                    if [ "$PICK" -eq 0 ]; then
                        echo "============================================"
                        echo "FAILED tests/test_predictor.py::test_pipeline"
                        echo "ERROR: NullPointerException at com.aiops.UserService:42"
                        echo "Traceback (most recent call last):"
                        echo "  File 'pipeline.py', line 88, in analyze"
                        echo "AssertionError: expected risk='HIGH' got 'LOW'"
                        echo "Build FAILED after 3 retries"
                        exit 1
                    fi
                    sleep 1
                    echo "All tests passed (142/142)"
                    echo "BUILD SUCCESS"
                '''
            }
        }
    }

    post {
        always {
            script {
                def result    = currentBuild.currentResult ?: 'UNKNOWN'
                def duration  = currentBuild.duration ?: 0
                def payload   = "{\"job_name\":\"${env.JOB_NAME}\",\"build_number\":${env.BUILD_NUMBER},\"status\":\"${result}\",\"duration_ms\":${duration},\"url\":\"${env.BUILD_URL}\"}"
                sh """
                    echo 'Notifying AIOps backend webhook...'
                    curl -fsS -X POST \\
                         -H 'Content-Type: application/json' \\
                         -d '${payload}' \\
                         http://backend:8000/api/jenkins/webhook \\
                      || echo 'webhook unreachable (backend offline?)'
                """
            }
        }
    }
}
